DROP TABLE IF EXISTS `cadforn`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `cadforn` (
  `data` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `solicitante` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `grupocont` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `centro` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `cnpj` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `razao` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `cnh` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `inscricao` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `incrimun` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `endereco` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `bairro` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `cidade` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `estado` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `cep` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `telefone` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `emailf` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `status` varchar(200) COLLATE utf8_unicode_ci NOT NULL DEFAULT 'Pendente',
  `ticket` int(40) NOT NULL AUTO_INCREMENT,
