  `fantasia` varchar(250) COLLATE utf8_unicode_ci NOT NULL,
  PRIMARY KEY (`ticket`)
) ENGINE=MyISAM AUTO_INCREMENT=468 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
