--
-- Table structure for table `cadmater`
--

DROP TABLE IF EXISTS `cadmater`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `cadmater` (
  `data` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `solicitante` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `descricao` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `ncm` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `peso` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `conversao` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `unidbasic` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `unidcomerc` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `uniddev` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `codfab` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `fab` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `classlote` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `centros` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `depositos` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `ticket` int(40) NOT NULL AUTO_INCREMENT,
  `status` varchar(200) COLLATE utf8_unicode_ci NOT NULL DEFAULT 'Pendente',
  `comentario` varchar(500) COLLATE utf8_unicode_ci NOT NULL,
  `grupomerc` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `controle` varchar(300) COLLATE utf8_unicode_ci NOT NULL,
  PRIMARY KEY (`ticket`)
) ENGINE=MyISAM AUTO_INCREMENT=601 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

