--
-- Table structure for table `cadmatp`
--

DROP TABLE IF EXISTS `cadmatp`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `cadmatp` (
  `data` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `solicitante` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `descricao` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `unimed` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `ncm` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `codfab` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `fab` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `centros` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `grupomerc` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `avaliacao` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `credito` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `ticket` int(11) NOT NULL AUTO_INCREMENT,
  `Status` varchar(200) COLLATE utf8_unicode_ci NOT NULL DEFAULT 'Pendente',
  `comentario` varchar(500) COLLATE utf8_unicode_ci NOT NULL,
  PRIMARY KEY (`ticket`),
  UNIQUE KEY `ticket` (`ticket`)
) ENGINE=MyISAM AUTO_INCREMENT=1517 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

