DROP TABLE IF EXISTS `contact`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `contact` (
  `data` varchar(40) COLLATE utf8_unicode_ci NOT NULL,
  `ticket` int(40) NOT NULL AUTO_INCREMENT,
  `solicitante` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `motivo` varchar(200) COLLATE utf8_unicode_ci NOT NULL,
  `mensagem` varchar(500) COLLATE utf8_unicode_ci NOT NULL,
  `status` varchar(200) COLLATE utf8_unicode_ci NOT NULL DEFAULT 'Pendente',
  `comentario` varchar(500) COLLATE utf8_unicode_ci NOT NULL,
  PRIMARY KEY (`ticket`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

